import { useParams } from "react-router-dom";
import { useEffect, useState } from "react";

function SalaryHistory() {
  const { id } = useParams();
  const [employee, setEmployee] = useState(null);

  useEffect(() => {
    const storedEmployees = JSON.parse(localStorage.getItem("employees")) || [];
    const emp = storedEmployees.find((e) => e.id === id);
    setEmployee(emp);
  }, [id]);

  if (!employee) return <p>No employee selected</p>;

  return (
    <div className="salary-container">
      <h2>Salary History</h2>

      <div className="employee-info">
        <p><strong>Name:</strong> {employee.name}</p>
        <p><strong>Employee ID:</strong> {employee.id}</p>
        <p><strong>Department:</strong> {employee.department}</p>
      </div>

      <table className="salary-table">
        <thead>
          <tr>
            <th>S No</th>
            <th>Salary</th>
            <th>Allowance</th>
            <th>Deduction</th>
            <th>Total</th>
            <th>Pay Date</th>
          </tr>
        </thead>
        <tbody>
          {employee.salaryHistory && employee.salaryHistory.length > 0 ? (
            employee.salaryHistory.map((record, index) => (
              <tr key={index}>
                <td>{index + 1}</td>
                <td>{record.salary}</td>
                <td>{record.allowance}</td>
                <td>{record.deduction}</td>
                <td>{record.total}</td>
                <td>{record.payDate}</td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="6">No salary history available</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

export default SalaryHistory;
